INSERT INTO Pages ( title, text, category_id, image_id) VALUES ('POBOŽNOSTI U ŽUPI', '<ul><li><b>Listopadske pobožnosti</b> – svaku večer pola sata prije svete mise molimo krunicu i litanije</li><li><b>Svibanjske pobožnosti</b> – svaku večer pola sata prije svete mise molimo krunicu i litanije</li><li><b>Pobožnost križnog puta</b> – u korizmeno vrijeme svake srijede i petka prije večernje mise</li><li><b>Molitva svete krunice</b> – kroz cijelu godinu pola sata prije svete mise</li><li><b>Molitva Časoslova</b> – ovisi o liturgijskom vremenu ali uglavnom se moli u sklopu svete mise</li><li><b>Euharistijska pobožnost</b> – četvrtkom nakon mise klanjanje pred Presvetim</li><li><b>Pobožnost sv. Petru</b> – srijedom pola sata prije svete mise</li><li><b>Pobožnost Presvetom Srcu Isusovu</b> – petkom prije svete mise</li></ul>', 8, NULL );
INSERT INTO Pages (title, text, category_id, image_id) VALUES ('KRŠTENJE', '<b>Sakrament krštenja</b> se dogovara barem 2 tjedna prije u uredovno vrijeme župnog ureda ili u susretu sa svećenikom nakon mise. </br></br><b>Za sakrament krštenja potrebno je pripremiti:</b> <ul style="margin-left:20px;"><li><b>Izvod iz matične knjige rođenih</b> za dijete (kopija)</li><li><b>Posvjedočenje za kumovanje</b> – ako kum/kuma nisu sa područja župe Sv. Petra, posvjedočenje za kumovanje mora uzeti u svojoj župi prebivališta</li><li><b>Dopuštenje za krštenje izvan župe</b> – ako obitelj stanuje u drugoj župi, potrebno je donijeti pismeno dopuštenje svoga župnika</li><li><b>Krsna svijeća i krsna haljinica</b> – potrebno je pripremiti</li></ul><br/><b>Ispovijed i pričest</b> – roditelji i kum/a pozvani su prije sakramenta krštenja ispovjediti se i pričestiti. </br><b>Pripremna kateheza</b> – redovito prije sakramenta krštenja roditelji sudjeluju u pripremnoj katehezi za sakrament krštenja. </br><b>Datum sakramenta</b> – slavi se po dogovoru; župnik preporučuje prvu nedjelju u mjesecu na misi u 11.00 sati, ali mogu doći i drugi dani. </br><b>Krštenje odraslih</b> – pretpostavlja pripravu koja se zove Katekumenat i događa se po dogovoru sa župnikom; sakramenti kršćanske inicijacije (krštenje, potvrda i pričest) se podjeljuju na Veliku subotu.', 9, NULL);
INSERT INTO Pages ( title, text, category_id, image_id) VALUES ('SVETA PRIČEST', '<b>Priprema za Svetu Pričest</b> traje cijelu školsku godinu. </br><b>Upis kandidata</b> – vrši se početkom rujna i upisuju se učenici trećeg razreda osnovne škole. </br><b>Župna kateheza</b> – održava se u vjeronaučnoj dvorani srijedom u 16.00 sati (ili po dogovoru na početku katehetske godine). </br></br><b>Priprema uključuje:</b> <ul style="margin-left:20px;"><li>Katehezu</li><li>Nedjeljnu misu u 11.00 sati – na koju bi djecu trebali pratiti roditelji</li><li>Aktivno uključivanje roditelja u vjerski odgoj djece prema sakramentu</li></ul> </br><b>Potvrdnica</b> – tijekom školske godine, a najkasnije do mjeseca travnja potrebno je vjeroučitelju dostaviti potvrdnicu. Potvrdnica je dokument u kojem je naznačeno da je dijete primilo sakrament krštenja, što je uvjet za primanje Pričesti. Izdaje ga župa u kojoj je krštenje obavljeno.', 10, NULL );
INSERT INTO Pages (title, text, category_id, image_id) VALUES ('KRIZMA', '<b>Sakrament Krizme</b> u našoj Šibenskoj biskupiji dijeli se na kraju osmog razreda. Naziva se <b>krizma</b> zbog svog bitnog obreda – pomazanja, a naziva se još i <b>potvrda</b> jer potvrđuje i osnažuje krsnu milost. </br></br><b>Upis kandidata</b> – vrši se početkom rujna i upisuju se učenici osmih razreda. </br><b>Župna kateheza</b> – održava se u vjeronaučnoj dvorani srijedom u 17.00 sati. </br></br><b>Priprema uključuje:</b> <ul style="margin-left:20px;"><li>Katehezu</li><li>Nedjeljnu misu u 11.00 sati</li><li>Aktivno uključivanje roditelja u vjerski odgoj djece prema sakramentu</li></ul> </br><b>Potvrdnica</b> – tijekom školske godine, a najkasnije do mjeseca travnja potrebno je dostaviti potvrdnicu. Potvrdnica je dokument u kojem je naznačeno da je dijete primilo sakrament krštenja i Prvu Pričest. Izdaje ga župa u kojoj se sakrament dogodio. </br><b>Posvjedočenje kuma</b> – dokument koji treba donijeti kum iz svoje župe kao potvrdu da može biti kum na krizmi ili na krštenju.', 11, NULL);
INSERT INTO Pages (title, text, category_id, image_id) VALUES ('EUHARISTIJA', '<b>Sveta misa</b> je izvor i vrhunac kršćanskoga života. Svaki vjernik je obavezan sudjelovati na nedjeljnoj svetoj misi. ', 12, NULL);
INSERT INTO Pages (title, text, category_id, image_id) VALUES ('ISPOVIJED', '<b>Sakramentu ispovijedi </b> u našoj župi se može pristupiti radnim danom prije mise ili po dogovoru. Moguće je dogovoriti osobni razgovor i susret i pojedinačnu ispovijed u bilo koje drugo vrijeme. ', 13, NULL);
INSERT INTO Pages (title, text, category_id, image_id) VALUES ('BOLESNIČKO POMAZANJE', '<p>Redovito prvim petkom u mjesecu župnik pohodi bolesnike koji su već prijavljeni za redoviti pohod bolesnicima. Moguće je dogovori bolesničko pomazanje i nakon svete mise ili u nekoj drugoj prilici kao i pohod bolesnicima u bolnici ili u Staračkom domu „Cvjetni dom“. Vaše bolesne i nemoćne ukućane možete prijaviti u župni ured ili obavijestiti svećenika nakon mise.</p>', 14, NULL);
INSERT INTO Pages (title, text, category_id, image_id) VALUES ('SVETI RED /DUHOVNI POZIV/REDOVNIK - REDOVNICA', '<p>Duhovni poziv je briga svake župne zajednice. U našoj župi posebno molimo za duhovna zvanja na svaki prvi četvrtak u mjesecu na zajedničkome uharistijskom klanjanju. Sve osobe koje promišljaju o duhovnom pozivu pozvane su razgovarati sa župnikom ili sa časnom sestrom aktivnom u našoj župi. </p>', 16, NULL);
INSERT INTO Pages (title, text, category_id, image_id) VALUES ('ŽENIDBA', '<b>Sakrament vjenčanja</b> u crkvi Sv. Petra – zaručnici koji se žele vjenčati trebaju se javiti u župni ured do godinu dana unaprijed prije vjenčanja. <br/><b>Datum vjenčanja</b> dogovaramo prema mogućnostima redovitog rasporeda misa. Preporuka je da se sakrament ženidbe slavi pod svetom misom, iako Obred vjenčanja može biti i bez svete mise. <br/><br/><b>Dokumenti</b> – nakon dogovora datuma vjenčanja zaručnici trebaju donijeti: <ul style="margin-left:20px;"><li>Krsni list za zaručnika i zaručnicu (ako su kršteni izvan župe)</li><li>Dokumenti iz Matičnog ureda (Potvrda o pretpostavci za vjenčanje u vjerskom obliku)</li><li>Potvrda o pohađanju zaručničkog tečaja</li><li>Ostale dokumente po potrebi</li></ul><br/><b>Dogovor s župnikom</b> – nakon donošenja dokumenata, zaručnici zajedno sa župnikom dogovaraju ostale detalje vjenčanja: kićenje crkve, cvijeće, sviranje, pjevanje. U crkvi Sv. Petra nije dozvoljeno svirati i pjevati pojedincima/osobama/zboru koji redovito ne sudjeluje u crkvenom pjevanju.', 15, NULL);
INSERT INTO Pages (title, text, category_id, image_id) VALUES ('SPROVOD', '<b>Sprovod</b> – sprovod pokojnika se dogovara u pogrebnom poduzeću „Čempresi d.o.o.“. Nakon dogovora o datumu i vremenu sprovoda potrebno je dogovoriti i u župnom uredu. Važno je napomenuti da pokojnik za kojeg se traži katolički sprovod treba biti krštena osoba koja nije tijekom života otpala od Katoličke Crkve. Sprovod se može učiniti isključivo za župljane župe sv. Petra. Doći u župni ured sa podacima o pokojniku te nakon ispunjenih podataka dogovoriti vrijeme svete mise zadušnice. <br/><b>Taksa</b> – za sprovod prema biskupijskom taksovniku je 50 €, za svetu misu 10 €. <br/><br/><b>Kršćanski sprovod</b> – proslava Kristova vazmenog otajstva: <ul style="margin-left:20px;"><li>»Sahranjujući svoje sinove i kćeri, Crkva puna vjere slavi Kristovo vazmeno otajstvo sa željom da oni koji su krštenjem postali sutjelesnici Krista umrloga i uskrsloga, s njime po smrti prijeđu u život, i to tako da u duši budu očišćeni te sa svetima i izabranima budu na nebo uzeti, a u tijelu da čekaju blaženu nadu – dolazak Kristov i uskrsnuće od mrtvih. Stoga Crkva za preminule prikazuje euharistijsku žrtvu Kristova vazma te uzdiže molitve za njihov pokoj da bi, uslijed uzajamnog zajedništva svih Kristovih udova, ono što jednima pribavlja duhovnu korist, drugima donosilo utjehu nade» (RSp 1).</li><li>»Crkva koja je, kao mati, sakramentalno nosila u svome krilu kršćane za njihova zemaljskog hodočašća, prati ih i na kraju puta, da ih preda ‘u Očeve ruke’. U Kristu, ona prikazuje Ocu djecu njegove milosti, a u nadi izručuje zemlji sjeme njihova tijela, koje će uskrsnuti u slavi. To se prikazanje u punini slavi euharistijskom žrtvom; blagoslovi koji prethode i koji slijede jesu blagoslovine» (KKC 1683).</li></ul>Prema tome, osnovni smisao kršćanskog sprovoda jest ispovijedanje vjere kršćanske zajednice u uskrsnuće tijela.', 18, NULL);
INSERT INTO Pages (title, text, category_id, image_id) VALUES ('BLAGOSLOV OBITELJI', '<b>Blagoslov obitelji</b> u župi svetog Petra može se događati tijekom cijele godine, a osobito u Božićno vrijeme, počevši od 27. prosinca. <ul style="margin-left:20px;"><li>Bilo bi lijepo da svi članovi obitelji, ukoliko nisu u pitanju nezaobilazne obveze i posao, budu prisutni na blagoslovu.</li><li>Kad svećenik ulazi u kuću, možete zapaliti jednu svijeću, staviti nastol križ i, ako imate, blagoslovljenu vodu i Bibliju.</li><li>Blagoslov obitelji je prilika za upoznavanje župnika sa župljanima i nadasve sa potrebama pojedinih osoba i obitelji.</li><li>Lijepo molimo župljane koji nas primaju u svoj dom da svoga kućnog ljubimca (psa), ako ga držite u dvorištu, privežete, a ako ga držite u svojim domovima i stanovima, zatvorite u prostoriju u koju ne ulazimo.</li></ul>', 17, NULL);
